package main

import (
    "database/sql"
    "fmt"
    "net/smtp"
    "os"
)

// Compliant: Secure credential management

// GOOD: Database credentials from environment
func connectToDatabase() (*sql.DB, error) {
    username := os.Getenv("DB_USER")
    password := os.Getenv("DB_PASSWORD")
    host := os.Getenv("DB_HOST")
    dbname := os.Getenv("DB_NAME")

    if username == "" || password == "" {
        return nil, fmt.Errorf("database credentials not configured")
    }

    connectionString := fmt.Sprintf("postgres://%s:%s@%s/%s", username, password, host, dbname)
    return sql.Open("postgres", connectionString)
}

// GOOD: API credentials from environment
func callExternalAPI() error {
    apiKey := os.Getenv("API_KEY")
    apiSecret := os.Getenv("API_SECRET")

    if apiKey == "" || apiSecret == "" {
        return fmt.Errorf("API credentials not configured")
    }

    client := NewAPIClient(apiKey, apiSecret)
    return client.MakeRequest()
}

// GOOD: Email credentials from configuration
type EmailConfig struct {
    SMTPHost string
    SMTPPort int
    Username string
    Password string
}

func loadEmailConfig() (*EmailConfig, error) {
    return &EmailConfig{
        SMTPHost: os.Getenv("SMTP_HOST"),
        SMTPPort: 587,
        Username: os.Getenv("SMTP_USERNAME"),
        Password: os.Getenv("SMTP_PASSWORD"),
    }, nil
}

func sendEmail(to, subject, body string) error {
    config, err := loadEmailConfig()
    if err != nil {
        return err
    }

    if config.Username == "" || config.Password == "" {
        return fmt.Errorf("email credentials not configured")
    }

    auth := smtp.PlainAuth("", config.Username, config.Password, config.SMTPHost)
    addr := fmt.Sprintf("%s:%d", config.SMTPHost, config.SMTPPort)

    return smtp.SendMail(addr, auth, config.Username, []string{to}, []byte(body))
}

// GOOD: JWT secret from environment
func getJWTSecret() ([]byte, error) {
    secret := os.Getenv("JWT_SECRET")
    if secret == "" {
        return nil, fmt.Errorf("JWT secret not configured")
    }
    return []byte(secret), nil
}

func generateToken(userID string) (string, error) {
    secret, err := getJWTSecret()
    if err != nil {
        return "", err
    }

    token := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.MapClaims{
        "user_id": userID,
        "exp":     time.Now().Add(time.Hour * 24).Unix(),
    })

    return token.SignedString(secret)
}

// GOOD: Cloud credentials using credential chain
import "github.com/aws/aws-sdk-go/aws/session"

func uploadToS3(filename string, data []byte) error {
    // AWS SDK automatically uses credential chain:
    // 1. Environment variables (AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY)
    // 2. IAM roles (for EC2 instances)
    // 3. AWS credentials file
    sess, err := session.NewSession()
    if err != nil {
        return fmt.Errorf("failed to create AWS session: %w", err)
    }

    // Use session for S3 operations
    _ = sess
    return nil
}

// GOOD: SSH key authentication
func connectToServer() error {
    user := os.Getenv("SSH_USER")
    keyPath := os.Getenv("SSH_KEY_PATH")
    host := os.Getenv("SSH_HOST")

    if user == "" || keyPath == "" || host == "" {
        return fmt.Errorf("SSH configuration not complete")
    }

    // Use SSH key file instead of password
    key, err := ioutil.ReadFile(keyPath)
    if err != nil {
        return fmt.Errorf("failed to read SSH key: %w", err)
    }

    // SSH connection with key authentication
    return connectWithKey(user, host, key)
}

// GOOD: Credential configuration struct
type Credentials struct {
    Database DatabaseCreds
    API      APICreds
    SMTP     SMTPCreds
}

type DatabaseCreds struct {
    User     string
    Password string
    Host     string
    Database string
}

func loadCredentials() (*Credentials, error) {
    return &Credentials{
        Database: DatabaseCreds{
            User:     os.Getenv("DB_USER"),
            Password: os.Getenv("DB_PASSWORD"),
            Host:     os.Getenv("DB_HOST"),
            Database: os.Getenv("DB_NAME"),
        },
        API: APICreds{
            Key:    os.Getenv("API_KEY"),
            Secret: os.Getenv("API_SECRET"),
        },
        SMTP: SMTPCreds{
            Username: os.Getenv("SMTP_USER"),
            Password: os.Getenv("SMTP_PASS"),
            Host:     os.Getenv("SMTP_HOST"),
        },
    }, nil
}

// GOOD: Validate all credentials are present
func (c *Credentials) Validate() error {
    if c.Database.User == "" || c.Database.Password == "" {
        return fmt.Errorf("database credentials incomplete")
    }
    if c.API.Key == "" || c.API.Secret == "" {
        return fmt.Errorf("API credentials incomplete")
    }
    return nil
}
